    # _ _ _ ROSE CHART _ _ _

    ui.bind_task_button(button_id="generate_dd_rosechart")
    @reactive.extended_task
    async def output_data_distribution_rose_chart(kwargs: dict):
        def _build(_kwargs=kwargs):
