        data,
        conditions,
        replicates,
        group_replicates,
        c_mode,
        color,
        palette,
        statistic,
        line,
        scatter,
        linear_fit,
        errorband,
        grid,
        title
    ):
        def _build():
            with warnings.catch_warnings():
                warnings.filterwarnings(
                    "ignore",
                    message="Starting a Matplotlib GUI outside of the main thread will likely fail",
                    category=UserWarning,
                )

