                    line=line,
                    scatter=scatter,
                    errorband=errorband,
                    linear_fit=linear_fit,
                    grid=grid,
                    title=title
                )

        # Run in executor, then store the figure in the reactive value
        return await asyncio.get_running_loop().run_in_executor(None, _build)

