            ) if input.conditions_ta() else \
            ui.update_selectize(
                id="conditions_ta",
                selected=S.TINTERVALSTATS.get()["Condition"].unique().tolist()
            )

        @reactive.Effect
        @reactive.event(input.replicates_reset_ta)
