class DataLoader:

    def __init__(self, **kwargs):
        self.noticequeue = kwargs.get('noticequeue', None)


    def GetDataFrame(self, filepath: str, **kwargs) -> pd.DataFrame:
        """
        Loads a DataFrame from a file based on its extension.
        Supported formats: CSV, Excel.
        """
        _, ext = op.splitext(filepath.lower())

        if ext not in ['.csv', '.xls', '.xlsx', '.xml', '.json', '.parquet']:
            Reporter(Level.error, f"File format: {ext} is not supported.", details=f"Supported formats include: .csv, .xls, .xlsx, .xml., .json, .parquet", noticequeue=self.noticequeue)
            return None

        match ext:
            case '.csv':
                return self._try_reading(filepath)
            case '.xls' | '.xlsx':
                return pd.read_excel(filepath)
            case '.xml':
                return pd.read_xml(filepath)
            case '.parquet':
                return pd.read_parquet(filepath)
            case '.json':
                return pd.read_json(filepath)
            case _:
                Reporter(Level.error, f"File format: {ext} is not supported.", details=f"Supported formats include: .csv, .xls, .xlsx, .xml., .json, .parquet", noticequeue=self.noticequeue)


    def ExtractStripped(self, df: pd.DataFrame, id_col: str, t_col: str, x_col: str, y_col: str, *args, mirror_y: bool = True, **kwargs) -> pd.DataFrame:
        """
        Prepare tracking data:
        - Extract only the 4 key columns.
        - Converts them to numeric, dropping rows with missing values.
        - Mirrors Y if requested.
        """

        try:
            if not all(col in df.columns for col in [id_col, t_col, x_col, y_col]):
                missing = [col for col in [id_col, t_col, x_col, y_col] if col not in df.columns]
                Reporter(Level.error, f"Specified columns were not found.", details=f"Missing columns: {missing}", noticequeue=self.noticequeue)
                return pd.DataFrame()

            df = df[[id_col, t_col, x_col, y_col]].apply(pd.to_numeric, errors='coerce').dropna().reset_index(drop=True)

        except Exception as e:
            Reporter(Level.error, f"Error in processing input DataFrame", details=f"{str(e)}", noticequeue=self.noticequeue)
            return pd.DataFrame()

        if mirror_y:
            """
            TrackMate may export y-coordinates mirrored.
            This does not affect statistics but leads to incorrect visualization.
            Here Y data is reflected across its midpoint for accurate directionality.
            """
            y_mid = (df[y_col].min() + df[y_col].max()) / 2
            df[y_col] = 2 * y_mid - df[y_col]

        return df.rename(columns={id_col: 'Track ID', t_col: 'Time point', x_col: 'X coordinate', y_col: 'Y coordinate'})


    def ExtractFull(self, df: pd.DataFrame, id_col: str, t_col: str, x_col: str, y_col: str, *args, mirror_y: bool = True, **kwargs) -> pd.DataFrame:
        """
        Prepare tracking data:
        - Converts chosen coordinate columns to numeric.
        - Mirrors Y if requested.
        - Renames the 4 key columns to standard names.
        - Keeps all other columns intact.
        - Normalizes column labels (e.g. 'CONTRAST_CH' → 'Contrast ch').
        """
        noticequeue = kwargs.get('noticequeue', None) if 'noticequeue' in kwargs else None

        try: 
            if not all(col in df.columns for col in [id_col, t_col, x_col, y_col]):
                missing = [col for col in [id_col, t_col, x_col, y_col] if col not in df.columns]
                Reporter(Level.error, f"Specified columns were not found.", details=f"Missing columns: {missing}", noticequeue=self.noticequeue)
                return pd.DataFrame()

            # convert only selected columns to numeric
            for c in [id_col, t_col, x_col, y_col]:
                df[c] = pd.to_numeric(df[c], errors="coerce")

            # drop rows missing key coordinates
            df = df.dropna(subset=[id_col, t_col, x_col, y_col]).reset_index(drop=True)
        except Exception as e:
            Reporter(Level.error, f"Error in processing input DataFrame", details=f"{str(e)}", noticequeue=self.noticequeue)
            return pd.DataFrame()

        # mirror Y if needed
        if mirror_y:
            y_mid = (df[y_col].min() + df[y_col].max()) / 2
            df[y_col] = 2 * y_mid - df[y_col]

        # rename main columns
        rename_map = {
            id_col: "Track ID",
            t_col: "Time point",
            x_col: "X coordinate",
            y_col: "Y coordinate",
        }
        df = df.rename(columns=rename_map)

        # normalize other column names
        try:
            df.columns = [self._clean_name(c) if c != 'Track ID' else c for c in df.columns]
        except Exception as e:
            pass


        self._py_numeric_df(df)

        return df


    def GetColumns(self, path: str, **kwargs) -> List[str]:
        """
        Returns a list of column names from the DataFrame.
        """

        df = self.GetDataFrame(path, noticequeue=self.noticequeue)  # or pd.read_excel(path), depending on file type
        return df.columns.tolist()


    def FindMatchingColumn(self, columns: List[str], lookfor: List[str], **kwargs) -> str:
        """
        Looks for matches with any of the provided strings.
        - First tries exact matches.
        - Then checks if the column starts with any of given terms.
        - Finally checks if any term is a substring of the column name.
        If no match is found, returns None.
        """

        # Normalize columns for matching
        normalized_columns = [
            (col, str(col).replace('_', ' ').strip().lower() if col is not None else '') for col in columns
        ]
        # Try exact matches first
        for col, norm_col in normalized_columns:
            for look in lookfor:
                if norm_col == look.lower():
                    return col

        # Then try startswith
        for col, norm_col in normalized_columns:
            for look in lookfor:
                if norm_col.startswith(look.lower()):
                    return col

        # Then try substring
        for col, norm_col in normalized_columns:
            for look in lookfor:
                if look.lower() in norm_col:
                    return col
        return None


    def _try_reading(self, path, encodings=("utf-8", "cp1252", "latin1", "iso8859_15"), **kwargs) -> pd.DataFrame:

        try:
            for enc in encodings:
                try:
                    return pd.read_csv(path, encoding=enc, low_memory=False)
                except UnicodeDecodeError:
                    continue
        except Exception as e:
            Reporter(Level.error, f"{str(e)} -> Failed to read file: {path}.", trace=traceback.format_exc(), noticequeue=self.noticequeue)


    def _py_numeric_df(self, df: pd.DataFrame) -> None:
        for col in df.columns:
            try: 
                df[col] = pd.to_numeric(df[col], errors='raise')
            except Exception as e: 
                continue  # quietly move on if conversion fails


    def _clean_name(self, name: str) -> str:
        name = str(name)
        name = name.replace("_", " ")
        name = re.sub(r"([a-z])([A-Z])", r"\1 \2", name)
        name = name.strip().capitalize()
        return name

from typing import *

class Level:

    info = "default"
    warning = "warning"
    error = "error"


class NoticeQueue:

    def __init__(self):
        self.cache = {
            "default": {
                "note": "Info",
                "messages": [],
                "details": [],
                "trace": [],
                "count": 0,
                "duration": [10, 15]
            },
            "warning": {
                "note": "Warning",
                "messages": [],
                "details": [],
                "trace": [],
                "count": 0,
                "duration": [15, 25]
            },
            "error": {
                "note": "Error",
                "messages": [],
                "details": [],
                "trace": [],
                "count": 0,
                "duration": None
            }
        }


    def Cleanse(self, level: str):
        if level in self.cache:
            self.cache[level] = {**self.cache[level], "messages": [], "details": [], "trace": [], "count": 0}
        if level == "all":
            for lvl in self.cache.keys():
                self.cache[lvl] = {**self.cache[lvl], "messages": [], "details": [], "trace": [], "count": 0}


    def Report(self, level: str, entry: str, entry_detail: str = None, *, entry_trace: str = None):
        if level in self.cache:
            message = list(self.cache[level].get("messages", []))
            detail = list(self.cache[level].get("details", []))
            trace = list(self.cache[level].get("trace", []))
            count = int(self.cache[level].get("count", 0)) + 1

            message.append(f'[{count}] {entry}')
            if entry_detail:
                detail.append(f'[{count}] {entry_detail}')
            if entry_trace:
                trace.append(f'[{count}] {entry_trace}')
            self.cache[level] = {**self.cache[level], "messages": message, "details": detail, "trace": trace, "count": count}


    def Emit(self):
        return self.cache



def Reporter(level: str, message: str, *, details: str = None, trace: str = None, noticequeue: Callable[[Level, str, str, str], None] = None) -> None:

    program_messages = {
        "default":  "PROGRAM INFO:     ",
        "warning":  "PROGRAM WARNING:  ",
        "error":    "PROGRAM ERROR:    "
    }

    if noticequeue is None:
        print("")
        print(f"{program_messages.get(level, 'UNKNOWN')}: {message}")
        if details:
            print(f"{18*' '}--> Details: {details}")
        if trace:
            print(f"{18*' '}--> Trace: {trace}")

    else:
        noticequeue.Report(level, message, details, entry_trace=trace)

# debounce_throttle.py
import functools
import time
import inspect
from typing import Callable, Optional, Any

from shiny import reactive


def DebounceCalc(delay_secs: int | float) -> Callable[[Callable[[], object]], Callable[[], object]]:
    """
    Decorator: delay propagating invalidations until `delay_secs` have passed
    *since the last* upstream invalidation.
    """
    def wrapper(f: Callable[[], object]) -> Callable[[], object]:
        when = reactive.Value[Optional[float]](None)
        trigger = reactive.Value(0)

        @reactive.calc
        def cached():
            # Wrap f in a calc so Shiny handles dependency tracking/caching.
            return f()

        @reactive.effect(priority=102)
        def primer():
            """
            Each time `cached()` invalidates, push the deadline out by `delay_secs`.
            """
            try:
                # Touch cached() to register dependency, but ignore its value/errors.
                cached()
            except Exception:
                ...
            finally:
                when.set(time.time() + delay_secs)

        @reactive.effect(priority=101)
        def timer():
            """
            If the deadline is in the future, wait; if it has passed, fire `trigger`.
            """
            deadline = when()
            if deadline is None:
                return

            remaining = deadline - time.time()
            if remaining <= 0:
                with reactive.isolate():
                    when.set(None)
                    trigger.set(trigger() + 1)
            else:
                reactive.invalidate_later(remaining)

        @reactive.calc
        @reactive.event(trigger, ignore_none=False)
        @functools.wraps(f)
        def debounced():
            return cached()

        return debounced

    return wrapper


def ThrottleCalc(delay_secs: int | float) -> Callable[[Callable[[], object]], Callable[[], object]]:
    """
    Decorator: propagate at most once every `delay_secs` even if upstream
    invalidates more frequently (first event gets through ASAP; subsequent ones
    are held until the window elapses).
    """
    def wrapper(f: Callable[[], object]) -> Callable[[], object]:
        last_signaled = reactive.Value[Optional[float]](None)  # when upstream last invalidated
        last_triggered = reactive.Value[Optional[float]](None) # when we last let a value through
        trigger = reactive.Value(0)

        @reactive.calc
        def cached():
            return f()

        @reactive.effect(priority=102)
        def primer():
            """
            Record that upstream invalidated (even if `cached()` errors).
            """
            try:
                cached()
            except Exception:
                ...
            finally:
                last_signaled.set(time.time())

        @reactive.effect(priority=101)
        def timer():
            """
            If we've never triggered, or the window has elapsed, trigger now.
            Otherwise, schedule a wake-up for the remaining window.
            """
            # Read to form dependencies
            signaled = last_signaled()
            triggered = last_triggered()

            # Nothing to do until we've seen at least one upstream signal.
            if signaled is None:
                return

            now = time.time()
            if triggered is None:
                # First-ever trigger goes through immediately.
                last_triggered.set(now)
                with reactive.isolate():
                    trigger.set(trigger() + 1)
                return

            elapsed = now - triggered
            if elapsed >= delay_secs:
                last_triggered.set(now)
                with reactive.isolate():
                    trigger.set(trigger() + 1)
            else:
                reactive.invalidate_later(delay_secs - elapsed)

        @reactive.calc
        @reactive.event(trigger, ignore_none=False)
        @functools.wraps(f)
        def throttled():
            return cached()

        return throttled

    return wrapper


def _unwrap_effect_callable(obj: Any) -> Callable[[], object]:
    """
    DebounceEffect must receive a plain callable. If a Shiny Effect_ object is
    mistakenly passed (e.g., by stacking @reactive.effect), try to unwrap to the
    underlying function; otherwise raise a helpful error.
    """
    if callable(obj):
        return obj

    # Best-effort unwrapping for Shiny Effect_ objects (internal API; may change).
    inner = getattr(obj, "_fn", None)
    if callable(inner):
        return inner

    raise TypeError(
        "DebounceEffect must decorate a plain function (do not stack with @reactive.effect). "
        f"Got non-callable object of type: {type(obj)!r}"
    )


def DebounceEffect(delay_secs: int | float) -> Callable[[Callable[[], object]], Callable[[], object]]:
    """
    Decorator: debounce an effect-like function.

    IMPORTANT: Use on an undecorated function. Do NOT also apply @reactive.effect.

    Example:
        @DebounceEffect(0.25)
        def do_stuff():
            ...
    """
    def wrapper(f: Callable[[], object]) -> Callable[[], object]:
        f_callable = _unwrap_effect_callable(f)

        async def _call_maybe_await(fn: Callable[[], object]) -> object:
            res = fn()
            if inspect.isawaitable(res):
                return await res
            return res

        # Per-effect state (do NOT share across all wrapped effects).
        when = reactive.Value[Optional[float]](None)
        trigger = reactive.Value(0)

        @reactive.effect(priority=102)
        async def primer():
            """
            Each time upstream invalidates, push the deadline out by `delay_secs`.
            NOTE: This calls the function to establish reactive dependencies.
            """
            try:
                await _call_maybe_await(f_callable)
            except Exception:
                ...
            finally:
                when.set(time.time() + delay_secs)

        @reactive.effect(priority=101)
        def timer():
            deadline = when()
            if deadline is None:
                return

            remaining = deadline - time.time()
            if remaining <= 0:
                with reactive.isolate():
                    when.set(None)
                    trigger.set(trigger() + 1)
            else:
                reactive.invalidate_later(remaining)

        @reactive.effect
        @reactive.event(trigger, ignore_none=False)
        @functools.wraps(f_callable)
        async def debounced_effect():
            await _call_maybe_await(f_callable)

        return debounced_effect

    return wrapper

