.file-preview-overlay {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: var(--overlay-bg);
    backdrop-filter: blur(1px);
    z-index: 9998;
    opacity: 0;
    transition: opacity 0.2s ease;
}

.file-preview-overlay.show {
    opacity: 1;
}

.file-preview-popup {
    position: fixed;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%) scale(0.95);
    background: var(--popup-bg);
    border-radius: 6px;
    box-shadow: 0 5px 15px var(--popup-shadow);
    z-index: 9999;
    min-width: 400px;
    max-width: 550px;
    max-height: 70vh;
    opacity: 0;
    transition: all 0.15s ease;
    overflow: hidden;
}

.file-preview-popup.show {
    opacity: 1;
    transform: translate(-50%, -50%) scale(1);
}

.file-preview-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 15px 20px;
    border-bottom: 1px solid var(--header-border);
    background: var(--header-bg);
}

.file-preview-header h3 {
    margin: 0;
    font-size: 20px;
    font-weight: 500;
    color: var(--text-color);
}

.file-preview-close {
    background: transparent;
    border: none;
    color: var(--subtext-color);
    width: 24px;
    height: 24px;
    cursor: pointer;
    font-size: 24px;
    line-height: 1;
    padding: 0;
    opacity: 0.5;
    transition: opacity 0.15s ease;
}

.file-preview-close:hover {
    opacity: 1;
    color: var(--close-hover-color);
}

.file-preview-content {
    padding: 20px;
    max-height: 50vh;
    overflow-y: auto;
}

.file-preview-empty {
    text-align: center;
    color: var(--subtext-color);
    padding: 20px;
    font-style: italic;
}

.file-preview-list {
    list-style: none;
    margin: 0;
    padding: 0;
}

.file-preview-item {
    display: flex;
    align-items: center;
    padding: 8px 10px;
    border-radius: 4px;
    margin-bottom: 6px;
    background: var(--item-bg);
    border: 0.5px solid var(--item-border);
}

.file-preview-item:hover {
    background: var(--item-hover-bg);
}

.file-preview-item:last-child {
    margin-bottom: 0;
}

.file-preview-icon {
    width: 32px;
    height: 32px;
    background: var(--subtext-color);
    border-radius: 4px;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-right: 12px;
    flex-shrink: 0;
}

.file-preview-icon svg {
    width: 16px;
    height: 16px;
    fill: var(--popup-bg);
}

.file-preview-info {
    flex: 1;
    min-width: 0;
}

.file-preview-name {
    font-size: 14px;
    font-weight: 400;
    color: var(--text-color);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.file-preview-size {
    font-size: 12px;
    color: var(--subtext-color);
    margin-top: 2px;
}

.file-preview-count {
    font-size: 14px;
    color: var(--text-color);
    margin-bottom: 15px;
    padding-bottom: 12px;
    border-bottom: 1px solid var(--header-border);
}
